using ModelContextProtocol.Server;
using System.ComponentModel;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Retrieves the value of a configuration key.")]
    public static string GetConfigValue(
        [Description("The configuration key to look up")] string key)
    {
        var config = AppConfiguration.Current;
        return config.TryGetValue(key, out var value)
            ? value
            : $"Key '{key}' not found. Available keys: {string.Join(", ", config.Keys)}";
    }

    [McpServerTool, Description("Lists all available configuration keys.")]
    public static string ListConfigKeys()
    {
        return string.Join("\n", AppConfiguration.Current.Keys.Order());
    }
}

using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Text.Json;

[McpServerResourceType]
public static class ConfigResources
{
    [McpServerResource(
        UriTemplate = "config://app/settings",
        Name = "App Settings",
        MimeType = "application/json"),
     Description("Returns the full application configuration as JSON.")]
    public static string GetAllSettings()
    {
        return JsonSerializer.Serialize(AppConfiguration.Current,
            new JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(
        UriTemplate = "config://app/environment",
        Name = "Environment Info",
        MimeType = "application/json"),
     Description("Returns current environment details (machine name, OS, runtime).")]
    public static string GetEnvironmentInfo()
    {
        var info = new
        {
            MachineName = Environment.MachineName,
            OsVersion = Environment.OSVersion.ToString(),
            Runtime = System.Runtime.InteropServices.RuntimeInformation.FrameworkDescription,
            ProcessorCount = Environment.ProcessorCount
        };
        return JsonSerializer.Serialize(info,
            new JsonSerializerOptions { WriteIndented = true });
    }
}

/// <summary>
/// Simple in-memory configuration store used by tools and resources.
/// Replace with IConfiguration or a database-backed store in production.
/// </summary>
public static class AppConfiguration
{
    public static Dictionary<string, string> Current { get; } = new()
    {
        ["app:name"] = "ConfigMcpServer",
        ["app:version"] = "1.0.0",
        ["feature:dark-mode"] = "true",
        ["feature:max-items"] = "50",
        ["logging:level"] = "Information"
    };
}

