using ModelContextProtocol.Server;

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddMcpServer(options =>
{
    options.ServerInfo = new() { Name = "ConfigMcpServer", Version = "1.0.0" };
    options.ServerInstructions = "MCP server exposing application configuration via tools and resources.";
})
.WithHttpTransport()
.WithToolsFromAssembly()
.WithResourcesFromAssembly();

var app = builder.Build();

app.MapMcp();                              // Streamable HTTP at /mcp
app.MapGet("/health", () => "ok");         // Health check for orchestrators

app.Run();

